```class Solution {
    public int distanceTraveled(int mainTank, int additionalTank) {
        int distance = 0;
        while (mainTank > 0) {
            mainTank -= 5;
            if (additionalTank >= 1) {
                additionalTank -= 1;
            }
            distance += 10; // 10 km per liter
        }
        return distance;
    }
}
